                     ></v-text-field>\r\n                      <v-text-field\r\n                          v-show=\"isLaoTab\"\r\n                          v-model=\"name\"\r\n                          :label=\"$t('DataPackage.Create.form.data_package_name')\"\r\n                          :rules=\"[$myValidator.SimpleValidate($t('Validate.required'))]\"\r\n                          outlined\r\n                          required\r\n                      ></v-text-field>\r\n                      <v-text-field\r\n                          v-show=\"isEngTab\"\r\n                          v-model=\"nameEng\"\r\n                          :label=\"$t('DataPackage.Create.form.data_package_name')\"\r\n                          :rules=\"[$myValidator.SimpleValidate($t('Validate.required'))]\"\r\n                          outlined\r\n                          required\r\n                      ></v-text-field>\r\n\r\n\r\n\r\n\r\n                      <div v-show=\"isLaoTab\" >\r\n\r\n\r\n\r\n                        <v-row justify=\"end\" v-show=\"previewImage !== null \">\r\n                          <v-btn\r\n                              class=\"mx-2\"\r\n                              fab\r\n                              dark\r\n                              small\r\n                              color=\"error\"\r\n                              @click=\"removeImage\"\r\n                          >\r\n                            <v-icon dark>\r\n                              mdi-close\r\n                            </v-icon>\r\n                          </v-btn>\r\n                        </v-row>\r\n                        <div class=\"upload-image mt-3\">\r\n\r\n                          <div class=\"content\" v-show=\"previewImage === null\">\r\n                            <i class=\"fas fa-plus-circle\"></i>\r\n                            <h3>{{ $t(\"Post.Create.form.picture\") }}</h3>\r\n\r\n                          </div>\r\n                          <img class=\"image-files\" :src=\"previewImage\" v-show=\"previewImage !== null\"/>\r\n\r\n                          <input\r\n\r\n                              type=\"file\"\r\n                              class=\"choose-file\"\r\n                              name=\"upload-image\"\r\n                              accept=\"image/*\"\r\n                              @change=\"UploadImage\"\r\n                          />\r\n                        </div>\r\n\r\n\r\n\r\n                      </div>\r\n\r\n\r\n                    </v-form>\r\n                    <div class=\"form-actions\">\r\n                      <v-btn class=\"mx-5\" plain @click=\"reset\">{{\r\n                          $t(\"DataPackage.Create.form.button.cancel\")\r\n                        }}\r\n                      </v-btn>\r\n                      <v-btn :disabled=\"!valid\" class=\"btn btn-create\" @click=\"submitForm\">\r\n                        {{ $t(\"DataPackage.Create.form.button.save\") }}\r\n                      </v-btn\r\n                      >\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n              </v-tab-item>\r\n            </v-tabs-items>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n  </div>\r\n</template>\r\n\r\n<script>\r\nimport {mapActions, mapGetters} from 'vuex'\r\n\r\nexport default {\r\n  name: \"Create\",\r\n\r\n  data() {\r\n    return {\r\n      code:'',\r\n      catePackageValue: '',\r\n      name: '',\r\n      nameEng: '',\r\n      description: '',\r\n      descriptionEng: '',\r\n      tab: null,\r\n      isLaoTab: false,\r\n      isEngTab: false,\r\n      uploadImage: null,\r\n\r\n      previewImage: null,\r\n\r\n      valid: true,\r\n    };\r\n  },\r\n\r\n  mounted() {\r\n\r\n    this.checkTabLang('ລາວ');\r\n  },\r\n\r\n  methods: {\r\n    checkTabLang(lang) {\r\n      console.log(lang)\r\n      if (lang == 'ລາວ' || lang == 'Lao') {\r\n        this.isLaoTab = true\r\n        this.isEngTab = false\r\n      